import React from "react";

function Geeting(props) {
  return (
    <div>
      <h1>Welcome to React</h1>
      <p>{props.value}</p>
    </div>
  );
}

function App() {
  return (
    <Geeting value="This is a prop value" />
  );
}
export default Geeting;
